import{_ as a,c as t,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Emparejamiento DM y control de acceso: protege tu asistente AI | Tutorial de Clawdbot","description":"Conoce el mecanismo de protección por emparejamiento DM de Clawdbot. Aprende cómo aprobar solicitudes de emparejamiento de remitentes desconocidos mediante CLI, listar solicitudes pendientes y gestionar la lista de permitidos. Este tutorial presenta el flujo de emparejamiento, uso de comandos CLI, configuración de políticas de acceso y mejores prácticas de seguridad, incluida solución de errores y comando doctor.","frontmatter":{"title":"Emparejamiento DM y control de acceso: protege tu asistente AI | Tutorial de Clawdbot","sidebarTitle":"Gestionar acceso de extraños","subtitle":"Emparejamiento DM y control de acceso: protege tu asistente AI","description":"Conoce el mecanismo de protección por emparejamiento DM de Clawdbot. Aprende cómo aprobar solicitudes de emparejamiento de remitentes desconocidos mediante CLI, listar solicitudes pendientes y gestionar la lista de permitidos. Este tutorial presenta el flujo de emparejamiento, uso de comandos CLI, configuración de políticas de acceso y mejores prácticas de seguridad, incluida solución de errores y comando doctor.","tags":["Introducción","Seguridad","Emparejamiento","Control de acceso"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"es/moltbot/moltbot/start/pairing-approval/index.md","filePath":"es/moltbot/moltbot/start/pairing-approval/index.md"}'),s={name:"es/moltbot/moltbot/start/pairing-approval/index.md"};function n(r,e,l,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="emparejamiento-dm-y-control-de-acceso-protege-tu-asistente-ai" tabindex="-1">Emparejamiento DM y control de acceso: protege tu asistente AI <a class="header-anchor" href="#emparejamiento-dm-y-control-de-acceso-protege-tu-asistente-ai" aria-label="Permalink to &quot;Emparejamiento DM y control de acceso: protege tu asistente AI&quot;">​</a></h1><h2 id="lo-que-lograras-al-finalizar" tabindex="-1">Lo que lograrás al finalizar <a class="header-anchor" href="#lo-que-lograras-al-finalizar" aria-label="Permalink to &quot;Lo que lograrás al finalizar&quot;">​</a></h2><p>Al completar este tutorial, podrás:</p><ul><li>✅ Comprender el mecanismo de protección por emparejamiento DM predeterminado</li><li>✅ Aprobar solicitudes de emparejamiento de remitentes desconocidos</li><li>✅ Listar y gestionar solicitudes de emparejamiento pendientes</li><li>✅ Configurar diferentes políticas de acceso DM (pairing/allowlist/open)</li><li>✅ Ejecutar doctor para verificar la configuración de seguridad</li></ul><h2 id="tu-desafio-actual" tabindex="-1">Tu desafío actual <a class="header-anchor" href="#tu-desafio-actual" aria-label="Permalink to &quot;Tu desafío actual&quot;">​</a></h2><p>Es posible que hayas configurado el canal de WhatsApp o Telegram y desees conversar con el asistente AI, pero te encuentras con los siguientes problemas:</p><ul><li>&quot;¿Por qué Clawdbot no responde cuando un extraño me envía un mensaje?&quot;</li><li>&quot;Recibí un código de emparejamiento, no sé qué significa&quot;</li><li>&quot;Quiero aprobar la solicitud de alguien, pero no sé qué comando usar&quot;</li><li>&quot;¿Cómo puedo confirmar quiénes están esperando aprobación?&quot;</li></ul><p>La buena noticia es: <strong>Clawdbot habilita el emparejamiento DM de forma predeterminada</strong>, para garantizar que solo los remitentes que autorices puedan conversar con el asistente AI.</p><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p>Cuando necesites:</p><ul><li>🛡 <strong>Proteger tu privacidad</strong>: garantizar que solo personas de confianza puedan conversar con el asistente AI</li><li>✅ <strong>Aprobar extraños</strong>: permitir que nuevos remitentes accedan a tu asistente AI</li><li>🔒 <strong>Control de acceso estricto</strong>: restringir los permisos de usuarios específicos</li><li>📋 <strong>Gestión por lotes</strong>: ver y gestionar todas las solicitudes de emparejamiento pendientes</li></ul><hr><h2 id="conceptos-clave" tabindex="-1">Conceptos clave <a class="header-anchor" href="#conceptos-clave" aria-label="Permalink to &quot;Conceptos clave&quot;">​</a></h2><h3 id="¿que-es-el-emparejamiento-dm" tabindex="-1">¿Qué es el emparejamiento DM? <a class="header-anchor" href="#¿que-es-el-emparejamiento-dm" aria-label="Permalink to &quot;¿Qué es el emparejamiento DM?&quot;">​</a></h3><p>Clawdbot se conecta a plataformas de mensajería reales (WhatsApp, Telegram, Slack, etc.). En estas plataformas, <strong>los mensajes privados (DM) se consideran entradas no confiables por defecto</strong>.</p><p>Para proteger tu asistente AI, Clawdbot proporciona un <strong>mecanismo de emparejamiento</strong>:</p><div class="info custom-block"><p class="custom-block-title">Flujo de emparejamiento</p><ol><li>Un remitente desconocido te envía un mensaje</li><li>Clawdbot detecta que este remitente no está autorizado</li><li>Clawdbot devuelve un <strong>código de emparejamiento</strong> (8 caracteres)</li><li>El remitente debe proporcionarte el código de emparejamiento</li><li>Aprobas el código mediante CLI</li><li>El ID del remitente se agrega a la lista de permitidos</li><li>El remitente puede conversar normalmente con el asistente AI</li></ol></div><h3 id="politica-dm-predeterminada" tabindex="-1">Política DM predeterminada <a class="header-anchor" href="#politica-dm-predeterminada" aria-label="Permalink to &quot;Política DM predeterminada&quot;">​</a></h3><p><strong>Todos los canales utilizan <code>dmPolicy=&quot;pairing&quot;</code> de forma predeterminada</strong>, lo que significa:</p><table tabindex="0"><thead><tr><th>Política</th><th>Comportamiento</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>Los remitentes desconocidos reciben un código de emparejamiento, el mensaje no se procesa (predeterminado)</td></tr><tr><td><code>allowlist</code></td><td>Solo permite remitentes de la lista <code>allowFrom</code></td></tr><tr><td><code>open</code></td><td>Permite todos los remitentes (requiere configuración explícita <code>&quot;*&quot;</code>)</td></tr><tr><td><code>disabled</code></td><td>Desactiva completamente la función DM</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Advertencia de seguridad</p><p>El modo <code>pairing</code> predeterminado es la opción más segura. No cambies al modo <code>open</code> a menos que tengas necesidades especiales.</p></div><hr><h2 id="🎒-preparativos-antes-de-comenzar" tabindex="-1">🎒 Preparativos antes de comenzar <a class="header-anchor" href="#🎒-preparativos-antes-de-comenzar" aria-label="Permalink to &quot;🎒 Preparativos antes de comenzar&quot;">​</a></h2><p>Asegúrate de haber:</p><ul><li>[x] Completado el tutorial de <a href="./../getting-started/">Inicio rápido</a></li><li>[x] Completado el tutorial de <a href="./../gateway-startup/">Iniciar Gateway</a></li><li>[x] Configurado al menos un canal de mensajería (WhatsApp, Telegram, Slack, etc.)</li><li>[x] Gateway está en ejecución</li></ul><hr><h2 id="sigue-conmigo" tabindex="-1">Sigue conmigo <a class="header-anchor" href="#sigue-conmigo" aria-label="Permalink to &quot;Sigue conmigo&quot;">​</a></h2><h3 id="paso-1-entender-el-origen-del-codigo-de-emparejamiento" tabindex="-1">Paso 1: Entender el origen del código de emparejamiento <a class="header-anchor" href="#paso-1-entender-el-origen-del-codigo-de-emparejamiento" aria-label="Permalink to &quot;Paso 1: Entender el origen del código de emparejamiento&quot;">​</a></h3><p>Cuando un remitente desconocido envía un mensaje a tu Clawdbot, recibirá una respuesta similar a la siguiente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>Características clave del código de emparejamiento</strong> (fuente: <code>src/pairing/pairing-store.ts</code>):</p><ul><li><strong>8 caracteres</strong>: fácil de ingresar y recordar</li><li><strong>Letras mayúsculas y números</strong>: evita confusiones</li><li><strong>Excluye caracteres confusos</strong>: no contiene 0, O, 1, I</li><li><strong>Validez de 1 hora</strong>: expira automáticamente después del tiempo</li><li><strong>Mantiene hasta 3 solicitudes pendientes</strong>: las solicitudes más antiguas se limpian automáticamente al exceder</li></ul><h3 id="paso-2-listar-solicitudes-de-emparejamiento-pendientes" tabindex="-1">Paso 2: Listar solicitudes de emparejamiento pendientes <a class="header-anchor" href="#paso-2-listar-solicitudes-de-emparejamiento-pendientes" aria-label="Permalink to &quot;Paso 2: Listar solicitudes de emparejamiento pendientes&quot;">​</a></h3><p>Ejecuta el siguiente comando en la terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>Si no hay solicitudes pendientes, verás:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Canales admitidos</p><p>La función de emparejamiento admite los siguientes canales:</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="paso-3-aprobar-solicitud-de-emparejamiento" tabindex="-1">Paso 3: Aprobar solicitud de emparejamiento <a class="header-anchor" href="#paso-3-aprobar-solicitud-de-emparejamiento" aria-label="Permalink to &quot;Paso 3: Aprobar solicitud de emparejamiento&quot;">​</a></h3><p>Aproba el acceso usando el código de emparejamiento proporcionado por el remitente:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>Lo que deberías ver</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Efecto después de aprobar</p><p>Después de aprobar, el ID del remitente (123456789) se agregará automáticamente a la lista de permitidos de ese canal, almacenada en: <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="paso-4-notificar-al-remitente-opcional" tabindex="-1">Paso 4: Notificar al remitente (opcional) <a class="header-anchor" href="#paso-4-notificar-al-remitente-opcional" aria-label="Permalink to &quot;Paso 4: Notificar al remitente (opcional)&quot;">​</a></h3><p>Si deseas notificar automáticamente al remitente, puedes usar la bandera <code>--notify</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>El remitente recibirá el siguiente mensaje (fuente: <code>src/channels/plugins/pairing-message.ts</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>Nota</strong>: la bandera <code>--notify</code> requiere que Clawdbot Gateway esté en ejecución y que el canal esté en estado activo.</p><h3 id="paso-5-verificar-que-el-remitente-puede-conversar-normalmente" tabindex="-1">Paso 5: Verificar que el remitente puede conversar normalmente <a class="header-anchor" href="#paso-5-verificar-que-el-remitente-puede-conversar-normalmente" aria-label="Permalink to &quot;Paso 5: Verificar que el remitente puede conversar normalmente&quot;">​</a></h3><p>Pide al remitente que envíe otro mensaje, el asistente AI debería responder normalmente.</p><hr><h2 id="punto-de-control-✅" tabindex="-1">Punto de control ✅ <a class="header-anchor" href="#punto-de-control-✅" aria-label="Permalink to &quot;Punto de control ✅&quot;">​</a></h2><p>Completa las siguientes verificaciones para confirmar que la configuración es correcta:</p><ul><li>[ ] Ejecutar <code>clawdbot pairing list &lt;channel&gt;</code> permite ver solicitudes pendientes</li><li>[ ] Usar <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> permite aprobar con éxito</li><li>[ ] El remitente aprobado puede conversar normalmente con el asistente AI</li><li>[ ] El código de emparejamiento expira automáticamente después de 1 hora (puede verificarse enviando otro mensaje)</li></ul><hr><h2 id="advertencias-comunes" tabindex="-1">Advertencias comunes <a class="header-anchor" href="#advertencias-comunes" aria-label="Permalink to &quot;Advertencias comunes&quot;">​</a></h2><h3 id="error-1-no-se-encuentra-el-codigo-de-emparejamiento" tabindex="-1">Error 1: No se encuentra el código de emparejamiento <a class="header-anchor" href="#error-1-no-se-encuentra-el-codigo-de-emparejamiento" aria-label="Permalink to &quot;Error 1: No se encuentra el código de emparejamiento&quot;">​</a></h3><p><strong>Mensaje de error</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>Posibles causas</strong>:</p><ul><li>El código de emparejamiento ha expirado (más de 1 hora)</li><li>El código de emparejamiento se ingresó incorrectamente (verifica mayúsculas/minúsculas)</li><li>El remitente no envió realmente el mensaje (el código de emparejamiento solo se genera cuando se recibe el mensaje)</li></ul><p><strong>Solución</strong>:</p><ul><li>Pide al remitente que envíe otro mensaje para generar un nuevo código de emparejamiento</li><li>Asegúrate de copiar el código de emparejamiento correctamente (presta atención a mayúsculas/minúsculas)</li></ul><h3 id="error-2-el-canal-no-admite-emparejamiento" tabindex="-1">Error 2: El canal no admite emparejamiento <a class="header-anchor" href="#error-2-el-canal-no-admite-emparejamiento" aria-label="Permalink to &quot;Error 2: El canal no admite emparejamiento&quot;">​</a></h3><p><strong>Mensaje de error</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>Posibles causas</strong>:</p><ul><li>El nombre del canal está mal escrito</li><li>El canal no admite la función de emparejamiento</li></ul><p><strong>Solución</strong>:</p><ul><li>Ejecuta <code>clawdbot pairing list</code> para ver la lista de canales admitidos</li><li>Usa el nombre correcto del canal</li></ul><h3 id="error-3-error-al-notificar" tabindex="-1">Error 3: Error al notificar <a class="header-anchor" href="#error-3-error-al-notificar" aria-label="Permalink to &quot;Error 3: Error al notificar&quot;">​</a></h3><p><strong>Mensaje de error</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>Posibles causas</strong>:</p><ul><li>Gateway no está en ejecución</li><li>La conexión del canal se ha desconectado</li><li>Problema de red</li></ul><p><strong>Solución</strong>:</p><ul><li>Confirma que Gateway está en ejecución</li><li>Verifica el estado de conexión del canal: <code>clawdbot channels status</code></li><li>No uses la bandera <code>--notify</code>, notifica manualmente al remitente</li></ul><hr><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><p>Este tutorial presentó el mecanismo de protección por emparejamiento DM de Clawdbot:</p><ul><li><strong>Seguridad predeterminada</strong>: todos los canales usan el modo <code>pairing</code> de forma predeterminada para proteger tu asistente AI</li><li><strong>Flujo de emparejamiento</strong>: los remitentes desconocidos reciben un código de emparejamiento de 8 caracteres, debes aprobarlo mediante CLI</li><li><strong>Comandos de gestión</strong>: <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>: listar solicitudes pendientes</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>: aprobar emparejamiento</li></ul></li><li><strong>Ubicación de almacenamiento</strong>: la lista de permitidos se almacena en <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>Expiración automática</strong>: las solicitudes de emparejamiento caducan automáticamente después de 1 hora</li></ul><p>Recuerda: <strong>el mecanismo de emparejamiento es la base de seguridad de Clawdbot</strong>, garantizando que solo las personas que autorices puedan conversar con el asistente AI.</p><hr><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="./../../faq/troubleshooting/">Solución de problemas: resolver problemas comunes</a></strong>.</p><p>Aprenderás:</p><ul><li>Diagnóstico rápido y verificación del estado del sistema</li><li>Resolver problemas de inicio de Gateway, conexión de canales, errores de autenticación, etc.</li><li>Métodos de solución de problemas para fallos en llamadas de herramientas y optimización del rendimiento</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Generación de código de emparejamiento (8 caracteres, excluye caracteres confusos)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>Almacenamiento y TTL de solicitudes de emparejamiento (1 hora)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>Comando de aprobación de emparejamiento</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>Generación de mensaje de código de emparejamiento</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>Almacenamiento de lista de permitidos</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td>Lista de canales que admiten <code>pairing</code></td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>Política DM predeterminada (pairing)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>: longitud del código de emparejamiento</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>: conjunto de caracteres del código de emparejamiento (excluye 0O1I)</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>: validez de la solicitud de emparejamiento (1 hora)</li><li><code>PAIRING_PENDING_MAX = 3</code>: número máximo de solicitudes pendientes</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>approveChannelPairingCode()</code>: aprobar código de emparejamiento y agregar a la lista de permitidos</li><li><code>listChannelPairingRequests()</code>: listar solicitudes de emparejamiento pendientes</li><li><code>upsertChannelPairingRequest()</code>: crear o actualizar solicitud de emparejamiento</li><li><code>addChannelAllowFromStoreEntry()</code>: agregar remitente a la lista de permitidos</li></ul></details>`,92)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
